import { useCallback, useEffect, useMemo, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { getSales, getSalesStats, deleteSale } from "../../api/saleApi";
import { getAuth } from "../../utils/auth";

export default function SaleList() {
  const [sales, setSales] = useState([]);
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [filter, setFilter] = useState("all");

  const navigate = useNavigate();
  const { role } = getAuth();
  const canManage = role === "admin" || role === "manager";
  const year = new Date().getFullYear();

  const load = useCallback(async () => {
    setError("");
    setLoading(true);

    try {
      const salesRes = await getSales();
      setSales(salesRes.data || []);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to load sales");
      setSales([]);
    } finally {
      setLoading(false);
    }

    try {
      const statsRes = await getSalesStats(year);
      setStats(statsRes.data || null);
    } catch {
      setStats(null);
    }
  }, [year]);

  useEffect(() => {
    load();
  }, [load]);

  const completedOnly = useMemo(
    () => sales.filter((s) => (s.payment_status || "").toLowerCase() === "completed"),
    [sales]
  );

  const totalsFromList = useMemo(() => {
    const totalRevenue = completedOnly.reduce((sum, s) => sum + Number(s.price || 0), 0);
    const months = new Set();
    completedOnly.forEach((s) => {
      const d = new Date(s.createdAt);
      months.add(`${d.getFullYear()}-${d.getMonth() + 1}`);
    });
    const avgMonthlyRevenue = months.size ? totalRevenue / months.size : 0;
    return { totalRevenue, avgMonthlyRevenue, totalSales: completedOnly.length };
  }, [completedOnly]);

  const totalRevenue = stats?.totalRevenue ?? totalsFromList.totalRevenue;
  const avgMonthlyRevenue = stats?.avgMonthlyRevenue ?? totalsFromList.avgMonthlyRevenue;
  const totalSales = stats?.totalSales ?? totalsFromList.totalSales;

  const filteredSales = useMemo(() => {
    if (filter === "all") return sales;
    return sales.filter((s) => (s.payment_status || "").toLowerCase() === filter);
  }, [sales, filter]);

  const onDelete = async (id) => {
    if (!canManage) return alert("Access denied");
    if (!window.confirm("Delete this sale record?")) return;

    try {
      await deleteSale(id);
      alert("Deleted");
      load();
    } catch (err) {
      alert(err.response?.data?.message || "Delete failed");
    }
  };

  const getStatusBadge = (status) => {
    const statusMap = {
      completed: "badgeSuccess",
      partial: "badgeWarning",
      pending: "badgeDanger",
    };
    return statusMap[status?.toLowerCase()] || "badge";
  };

  return (
    <div className="page">
      {/* Page Header */}
      <div className="pageHead">
        <div>
          <div className="pageTitle">Sales Management</div>
          <div className="pageSub">Track and manage vehicle sales and payments</div>
        </div>
      </div>

      {/* KPI Cards */}
      <div className="kpiGrid">
        <div className="kpiCard">
          <div className="kpiLabel">Total Sales</div>
          <div className="kpiValue">{loading ? "—" : sales.length}</div>
          <div className="kpiSub">All transactions</div>
        </div>

        <div className="kpiCard">
          <div className="kpiLabel">Completed Sales</div>
          <div className="kpiValue">{loading ? "—" : completedOnly.length}</div>
          <div className="kpiSub">Revenue processed</div>
        </div>

        <div className="kpiCard">
          <div className="kpiLabel">Total Revenue</div>
          <div className="kpiValue" style={{ fontSize: "20px" }}>
            {loading ? "—" : `Rs ${Math.round(totalRevenue / 1000)}K`}
          </div>
          <div className="kpiSub">Year {year}</div>
        </div>

        <div className="kpiCard">
          <div className="kpiLabel">Avg Monthly</div>
          <div className="kpiValue" style={{ fontSize: "20px" }}>
            {loading ? "—" : `Rs ${Math.round(avgMonthlyRevenue / 1000)}K`}
          </div>
          <div className="kpiSub">Average revenue</div>
        </div>
      </div>

      {/* Filter & Actions Card */}
      <div className="card cardPad" style={{ marginBottom: 14 }}>
        <div className="row" style={{ alignItems: "center", flexWrap: "wrap" }}>
          <div>
            <div className="sectionTitle">Sales Management</div>
            <div className="sub">Filter and manage your sales records</div>
          </div>

          <div style={{ display: "flex", gap: 10, alignItems: "center", marginLeft: "auto", flexWrap: "wrap" }}>
            <select
              className="select"
              style={{ minWidth: 180 }}
              value={filter}
              onChange={(e) => setFilter(e.target.value)}
            >
              <option value="all">All Sales</option>
              <option value="completed">Completed</option>
              <option value="partial">Partial</option>
              <option value="pending">Pending</option>
            </select>

            {canManage && (
              <button className="btn btnPrimary" onClick={() => navigate("/sales/add")}>
                ➕ Add Sale
              </button>
            )}
            <button 
              className="btn" 
              onClick={load} 
              disabled={loading}
              style={{ minWidth: 100 }}
            >
              {loading ? "Loading..." : "Refresh"}
            </button>
          </div>
        </div>
      </div>

      {/* Sales Table */}
      <div className="card cardPad">
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ borderBottom: "2px solid var(--border-light)" }}>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Vehicle</th>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Customer</th>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Price</th>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Status</th>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Date</th>
              <th style={{ padding: "12px", textAlign: "right", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Actions</th>
            </tr>
          </thead>

          <tbody>
            {filteredSales.map((s) => (
              <tr key={s._id} style={{ borderBottom: "1px solid var(--border-light)", transition: "background 0.2s" }}>
                <td style={{ padding: "12px", fontWeight: "500", color: "var(--text)" }}>
                  {s.vehicle?.brand ? `${s.vehicle.brand} ${s.vehicle.model || s.vehicle.type || ""}` : "—"}
                </td>
                <td style={{ padding: "12px", color: "var(--text-secondary)" }}>{s.customer?.name || "—"}</td>
                <td style={{ padding: "12px", fontWeight: "500", color: "var(--primary)" }}>
                  Rs {Number(s.price || 0).toLocaleString()}
                </td>
                <td style={{ padding: "12px" }}>
                  <span className={`badge ${getStatusBadge(s.payment_status)}`}>
                    {s.payment_status || "—"}
                  </span>
                </td>
                <td style={{ padding: "12px", color: "var(--text-secondary)" }}>
                  {s.createdAt ? new Date(s.createdAt).toLocaleDateString() : "—"}
                </td>
                <td style={{ padding: "12px", textAlign: "right" }}>
                  {canManage ? (
                    <>
                      <button 
                        className="btn btnSmall" 
                        onClick={() => navigate(`/sales/edit/${s._id}`)}
                        style={{ marginRight: 6 }}
                      >
                        ✏️ Edit
                      </button>
                      <button
                        className="btn btnSmall"
                        onClick={() => onDelete(s._id)}
                        style={{ background: "var(--danger)", color: "white" }}
                      >
                        🗑️ Delete
                      </button>
                    </>
                  ) : (
                    <span style={{ color: "var(--text-secondary)" }}>—</span>
                  )}
                </td>
              </tr>
            ))}

            {!loading && filteredSales.length === 0 && (
              <tr>
                <td colSpan="6" style={{ padding: "40px", textAlign: "center", color: "var(--text-secondary)" }}>
                  {filter !== "all" ? "No sales found with this status" : "No sales records yet"}
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}
